import{_ as o,o as s,c as a,a2 as t}from"./chunks/framework.Bix3-HpO.js";const m=JSON.parse('{"title":"Kemoku Blocks","description":"Kemoku Plugin - Blocks","frontmatter":{"title":"Kemoku Blocks","description":"Kemoku Plugin - Blocks","weight":60,"extra":{"order":60},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/kemoku/blocks"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/kemoku/blocks"}],["meta",{"property":"og:title","content":"Kemoku Blocks"}],["meta",{"property":"og:description","content":"Kemoku Plugin - Blocks"}],["meta",{"name":"twitter:title","content":"Kemoku Blocks"}],["meta",{"name":"twitter:description","content":"Kemoku Plugin - Blocks"}]]},"headers":[],"relativePath":"docs/kemoku/blocks.md","filePath":"docs/kemoku/blocks.md"}'),i={name:"docs/kemoku/blocks.md"};function n(r,e,l,c,d,u){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="kemoku-plugin-blocks" tabindex="-1">Kemoku Plugin Blocks <a class="header-anchor" href="#kemoku-plugin-blocks" aria-label="Permalink to &quot;Kemoku Plugin Blocks&quot;">​</a></h1><p>There are multiple blocks and shortcodes available for you to present your website information. It is recommended to use native blocks instead of shortcodes, however if for some reason you&#39;re still using a version of WordPress lower than 5.0, you can use shortcodes as well.</p><p>There are 2 groups of blocks:</p><ol><li>Blocks you can use on all pages</li><li>Blocks you can use on review pages</li></ol><p>This page describes the blocks you can use on all pages.</p><hr><h2 id="using-blocks" tabindex="-1">Using Blocks <a class="header-anchor" href="#using-blocks" aria-label="Permalink to &quot;Using Blocks&quot;">​</a></h2><p>Below are the blocks available in Kemoku plugin you can use on all pages:</p><ul><li>Reviews Listings (Tables and Grids)</li><li>Review CTA</li><li>Review Bonus</li></ul><h3 id="reviews-listings" tabindex="-1">Reviews Listings <a class="header-anchor" href="#reviews-listings" aria-label="Permalink to &quot;Reviews Listings&quot;">​</a></h3><p>Simply add the block, select reviews you want to display, adjust the settings and they are ready.</p><p><code>💁 since version 1.5</code> you can choose reviews manually, filter them by category or by tag(s).</p><p>You can select a review category and all reviews in that category will be displayed. You can also set a limit, for example display 10 reviews in &quot;Sports&quot; category.</p><p>Besides categories, you can filter reviews by review tags as well. In difference to categories, you can select multiple tags. For example, display 12 reviews tagged &quot;USA&quot; and &quot;Canada&quot;. You can combine those 2 together, for example display 10 reviews in &quot;Sports&quot; category tagged &quot;USA&quot; and &quot;Canada&quot;.</p><p><code>💁 since version 1.5.7</code> you can overwrite bonus and affiliate link values on each listing block.</p><p><code>💁 since version 1.5.8</code> you can enable filters, sorting and load more button on listing blocks.</p><p><code>💁 since version 1.6.3</code> you can display terms in a popup.</p><p><code>💁 since version 2.0.0</code> you can display filter reviews by the visitor&#39;s country and display a country support badges on listing items.</p><p><code>💁 since version 2.2.0</code> you can overwrite bonus codes for individual items in your tables and grids.</p><p><code>💁 since version 2.2.0</code> you can filter review tables and grids by specific custom fields like payment methods, currencies, sports, services, countries and US states.</p><h4 id="table" tabindex="-1">Table <a class="header-anchor" href="#table" aria-label="Permalink to &quot;Table&quot;">​</a></h4><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-reviews-table-block-frontend.jpg" alt="Kemoku Table Block"></p><h4 id="table-payments" tabindex="-1">Table: Payments <a class="header-anchor" href="#table-payments" aria-label="Permalink to &quot;Table: Payments&quot;">​</a></h4><p><code>💁 since version 1.6.5</code></p><p>New table design for showcasing review payment options such as different payment methods, payout speeds. You can use the filtering, sorting and limiting options with this table as well. The styles of this table can be easily customized, learn how to do that <a href="/docs/kemoku/how-to#how-to-customize-&quot;table:-payments&quot;-block-design">here</a>.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-reviews-table-payments-block-frontend.jpg" alt="Kemoku Table Payments Block"></p><h4 id="grid" tabindex="-1">Grid <a class="header-anchor" href="#grid" aria-label="Permalink to &quot;Grid&quot;">​</a></h4><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-reviews-grid-block-frontend.jpg" alt="Kemoku Grid Block"></p><h4 id="grid-bonus" tabindex="-1">Grid: Bonus <a class="header-anchor" href="#grid-bonus" aria-label="Permalink to &quot;Grid: Bonus&quot;">​</a></h4><p><code>💁 since version 1.6.8</code></p><p>New grid design for showcasing review bonuses. You can use the filtering, sorting and limiting options with this grid as well. The styles of this grid can be easily customized, learn how to do that <a href="/docs/kemoku/how-to#how-to-customize-&quot;grid:-bonus&quot;-block-design">here</a>.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-reviews-grid-bonus-block-frontend.jpg" alt="Kemoku Grid Bonus Block"></p><h4 id="filters-and-sorting" tabindex="-1">Filters and Sorting <a class="header-anchor" href="#filters-and-sorting" aria-label="Permalink to &quot;Filters and Sorting&quot;">​</a></h4><p>Both for tables and grids, this is what the filters and sorting popup looks like. And you can customize every part of it as described <a href="/docs/kemoku/listing-tools">here</a>.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-reviews-listing-tools.jpg" alt="Kemoku Listing Filters and Sorting"></p><h3 id="review-cta" tabindex="-1">Review CTA <a class="header-anchor" href="#review-cta" aria-label="Permalink to &quot;Review CTA&quot;">​</a></h3><p>Simply add the block, fill in the heading (optional), content and button/link fields and it&#39;s ready.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-review-cta-block-frontend.jpg" alt="Kemoku CTA Block"></p><h3 id="review-bonus" tabindex="-1">Review Bonus <a class="header-anchor" href="#review-bonus" aria-label="Permalink to &quot;Review Bonus&quot;">​</a></h3><p><code>💁 since version 2.3.0</code></p><p>New card block for showcasing a single review&#39;s bonus offer. Displays the review logo, a bonus heading label, the bonus text, an optional copy-able bonus code, an affiliate link button, and optional terms.</p><p>The block can target a specific review via the <strong>Review</strong> field, or leave it empty to automatically use the current review page. You can override the bonus text, bonus code, affiliate link, and terms directly in the block fields.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-review-bonus-block-frontend.jpg" alt="Kemoku Review Bonus Block"></p><h3 id="blocks-vs-shortcodes" tabindex="-1">Blocks vs Shortcodes <a class="header-anchor" href="#blocks-vs-shortcodes" aria-label="Permalink to &quot;Blocks vs Shortcodes&quot;">​</a></h3><p>You can use all blocks as shortcodes as well. Check out <a href="/docs/kemoku/shortcodes">Shortcodes</a> for more information.</p><blockquote><p>It is highly recommended to use blocks instead of shortcodes. Future blocks may not have shortcodes.</p></blockquote>',46)])])}const h=o(i,[["render",n]]);export{m as __pageData,h as default};
